import{_ as t,o as p,c as i,a6 as s,eD as r,eE as e,eF as l,eG as n,eH as o,eI as _,eJ as c,eK as d}from"./chunks/framework.UYVGz2W_.js";const u=JSON.parse('{"title":"タスクの割り当て","description":"","frontmatter":{},"headers":[],"relativePath":"ja/assignation/index.md","filePath":"ja/assignation/index.md"}'),m={name:"ja/assignation/index.md"};function h(g,a,f,x,b,P){return p(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="タスクの割り当て" tabindex="-1">タスクの割り当て <a class="header-anchor" href="#タスクの割り当て" aria-label="Permalink to “タスクの割り当て”">​</a></h1><p>キットゥでは、タスクは制作のさまざまな側面を計画、整理、追跡するために使用される基本要素です。</p><p>タスクをユーザーに割り当てることで、以下のような利点があります。</p><ul><li>各タスクの担当者が明確になります。</li><li>ユーザーは割り当てられたタスクを認識します。</li><li>ユーザーは各タスクに費やした時間を記録できます。</li><li>個々の作業負荷を監視できます。</li><li>ユーザーごとのタスクグループは、詳細なタスクタイプページで表示されます。</li><li>チームスケジュールは、スタジオの概要を提供します。</li><li>チームの生産性を予測できます。</li><li>チームの実際のパフォーマンスを追跡できます。</li></ul><h2 id="チームにユーザーを追加する" tabindex="-1">チームにユーザーを追加する <a class="header-anchor" href="#チームにユーザーを追加する" aria-label="Permalink to “チームにユーザーを追加する”">​</a></h2><p>チームの準備に関するセクション](../team)では、Kitsuにユーザーを追加する方法、そのユーザーの権限レベルを設定する方法、およびユーザーを部署にリンクする方法について説明しています。</p><p>::: ヒント ユーザーにタスクを割り当てるには、まずそのユーザーをプロダクションに追加する必要があります。プロダクション外のユーザーにはタスクを割り当てることができないことにご注意ください。 :::</p><p>まず、ユーザーをプロダクションに追加しましょう。プロジェクト内で、ページ上部のドロップダウンメニューから「チーム」ページを選択します。</p><p><img src="'+r+'" alt="ドロップダウンメニューのチーム"></p><p>このページでは、このプロジェクトに割り当てられたすべてのユーザーを確認できます。 プロジェクトを新規作成したばかりの場合は、このページは空欄となります。 特定のプロジェクトのチームページに素早く移動するには、ドロップダウンメニューでプロジェクト名を選択します。</p><p><img src="'+e+'" alt="チームページ"></p><p>::: 警告 権限と部門は、<strong>スタジオレベル</strong>で設定されます。制作レベルでは、これらの設定を変更することはできません。 :::</p><h2 id="タスクの割り当て方法" tabindex="-1">タスクの割り当て方法 <a class="header-anchor" href="#タスクの割り当て方法" aria-label="Permalink to “タスクの割り当て方法”">​</a></h2><h3 id="グローバルページからのタスクの割り当て" tabindex="-1">グローバルページからのタスクの割り当て <a class="header-anchor" href="#グローバルページからのタスクの割り当て" aria-label="Permalink to “グローバルページからのタスクの割り当て”">​</a></h3><p>すべてのユーザーをプロダクションに追加したら、最初のタスクを割り当てましょう！</p><p>::: ヒント 定義 キットでは、各タスクタイプのタスクは、以下の図のように、タスクセルのステータスによって視覚的に表現されます。 :::</p><p><img src="'+l+'" alt="タスクの割り当て"></p><p>割り当てたいタスクのステータスをクリックします。</p><p>すると、画面の右側にコメントパネルが表示され、そのタスクの設定に関するさまざまなオプションが表示されます。</p><p><img src="'+n+'" alt="青いメニュー"></p><p>次に、割り当てボタンをクリックして割り当てダイアログを開きます</p><p><img src="'+o+'" alt="選択した人"></p><p>ここで、タスクにユーザーを割り当てることができます。ボックスをクリックすると、利用可能なユーザーの一覧がポップアップ表示されます。または、ユーザー名を入力すると、特定のユーザーをすばやく絞り込むことができます。割り当てたいユーザーを選択し、「<strong>assign to selected task</strong>」ボタンをクリックして割り当てを完了します。</p><p>::: ヒント メモ 1つのタスクに複数のユーザーを割り当てることができます :::</p><p>また、同時に複数のタスクにユーザーを割り当てることもできます。 まず、割り当てたいタスクを選択する必要があります。 キーボードの <strong>Ctrl/Cmd</strong> キーを押しながら、選択したいタスクをクリックします。 あるいは、<strong>Shift</strong> キーを使用して、タスクの範囲を選択することもできます。 選択したタスクが青くハイライトされていることが分かるでしょう。</p><p><img src="'+_+'" alt="複数の担当者を割り当て"></p><p>タスクをハイライトしたら、割り当てるユーザーを選択し、<strong>[確認]</strong>ボタンをクリックして選択を確定します。同様に、<strong>[選択から割り当て解除]</strong>オプションを使用して、これらの割り当てを解除することもできます。</p><p>これで、各タスクのステータスの横に担当者のアバターが表示されます。</p><p><img src="'+c+'" alt="割り当てられた人"></p><p>スプレッドシートの上部にある<strong>[割り当ての表示/非表示]</strong>ボタンを使用して、タスク割り当ての表示/非表示を切り替えることができます <img src="'+d+'" alt="割り当ての非表示">。</p><p>タスクの割り当ては、ユーザーの役割に応じて、ユーザーが閲覧できる内容を決定する場合があることに留意してください（例えば、ベンダーは何かを閲覧する前にタスクに割り当てられる必要があります）。</p><p>割り当てが完了すると、全員が各自のタスクと責任を把握できます！</p><h3 id="詳細なタスクタイプページからのタスクの割り当て" tabindex="-1">詳細なタスクタイプページからのタスクの割り当て <a class="header-anchor" href="#詳細なタスクタイプページからのタスクの割り当て" aria-label="Permalink to “詳細なタスクタイプページからのタスクの割り当て”">​</a></h3><p>詳細なタスクタイプページからタスクを割り当てることもできます。これにアクセスするには、タスクタイプの列見出しをクリックします。</p><p>次に、ステータスをクリックしてコメントパネルを開きます。そこから、グローバルページと同じオプションが利用できます。ユーザーに割り当てるタスクを1つまたは複数同時に選択できます。</p>',35)])])}const S=t(m,[["render",h]]);export{u as __pageData,S as default};
